import threading
from decimal import Decimal
from typing import Dict, Optional
from dataclasses import dataclass
from enum import Enum
import time

class TransactionType(Enum):
    DEPOSIT = "deposit"
    WITHDRAWAL = "withdrawal"
    TRANSFER = "transfer"

@dataclass
class Transaction:
    transaction_id: str
    account_id: str
    amount: Decimal
    transaction_type: TransactionType
    target_account_id: Optional[str] = None

class Account:
    def __init__(self, account_id: str, initial_balance: Decimal = Decimal('0')):
        self.account_id = account_id
        self._balance = initial_balance
        self._lock = threading.Lock()
        self._version = 0
    
    def get_balance(self) -> Decimal:
        with self._lock:
            return self._balance
    
    def _update_balance(self, amount: Decimal) -> bool:
        self._balance += amount
        self._version += 1
        return True

class AccountManager:
    def __init__(self):
        self._accounts: Dict[str, Account] = {}
        self._accounts_lock = threading.Lock()
        self._processed_transactions = set()
        self._transactions_lock = threading.Lock()
    
    def create_account(self, account_id: str, initial_balance: Decimal = Decimal('0')) -> Account:
        with self._accounts_lock:
            if account_id not in self._accounts:
                self._accounts[account_id] = Account(account_id, initial_balance)
            return self._accounts[account_id]
    
    def get_account(self, account_id: str) -> Optional[Account]:
        with self._accounts_lock:
            return self._accounts.get(account_id)
    
    def process_transaction(self, transaction: Transaction) -> bool:
        with self._transactions_lock:
            if transaction.transaction_id in self._processed_transactions:
                return False
            self._processed_transactions.add(transaction.transaction_id)
        
        try:
            if transaction.transaction_type == TransactionType.DEPOSIT:
                return self._process_deposit(transaction)
            elif transaction.transaction_type == TransactionType.WITHDRAWAL:
                return self._process_withdrawal(transaction)
            elif transaction.transaction_type == TransactionType.TRANSFER:
                return self._process_transfer(transaction)
            return False
        except Exception:
            with self._transactions_lock:
                self._processed_transactions.discard(transaction.transaction_id)
            raise
    
    def _process_deposit(self, transaction: Transaction) -> bool:
        account = self.get_account(transaction.account_id)
        if not account:
            return False
        
        with account._lock:
            account._update_balance(transaction.amount)
        return True
    
    def _process_withdrawal(self, transaction: Transaction) -> bool:
        account = self.get_account(transaction.account_id)
        if not account:
            return False
        
        with account._lock:
            if account._balance >= transaction.amount:
                account._update_balance(-transaction.amount)
                return True
            return False
    
    def _process_transfer(self, transaction: Transaction) -> bool:
        if not transaction.target_account_id:
            return False
        
        source_account = self.get_account(transaction.account_id)
        target_account = self.get_account(transaction.target_account_id)
        
        if not source_account or not target_account:
            return False
        
        accounts = sorted([source_account, target_account], key=lambda a: a.account_id)
        
        with accounts[0]._lock:
            with accounts[1]._lock:
                if source_account._balance >= transaction.amount:
                    source_account._update_balance(-transaction.amount)
                    target_account._update_balance(transaction.amount)
                    return True
                return False

def process_financial_transactions(manager: AccountManager, transactions: list) -> Dict[str, bool]:
    results = {}
    for transaction in transactions:
        try:
            results[transaction.transaction_id] = manager.process_transaction(transaction)
        except Exception as e:
            results[transaction.transaction_id] = False
